mapper.select:
select 

from T_COMP_RISKRULE 



            and L_RULE_NO in ${lRuleNo}


            and VC_RULE_CODE = #{vcRuleCode}


            and VC_RULE_DESCIBE  like CONCAT(#{vcRuleDescibe},'%')




            and C_RULE_TYPE = #{rule_type}


            and C_LEGAL_TYPE = #{legal_type}


            and L_VALID_BEGINDATE >= #{begin_date}


            and L_VALID_ENDDATE <= #{end_date}


            and C_VALID_STATUS = #{status}



            and VC_NUMERATOR_CODE in ${numerator_ids}



select distinct  VC_FUND_ID_O32 fundid, VC_FUND_NAME_O32 fundname from PRT_PORTINFO 



           and VC_PORT_TYPE_1 = #{type1}


           and VC_PORT_TYPE_2 = #{type2}

       AND  vc_fund_id_o32 IS NOT NULL
       AND  vc_fund_id_o32 NOT LIKE '%-%' 

       order by VC_FUND_ID_O32 asc



select distinct  VC_ASSET_ID_O32 assetid from PRT_PORTINFO 


           and VC_PORT_TYPE_1 = #{type1}


           and VC_PORT_TYPE_2 = #{type2}


           and VC_FUND_ID_O32 = #{fundid}

        AND  vc_fund_id_o32 IS NOT NULL
       AND  vc_fund_id_o32 NOT LIKE '%-%' 
       AND VC_ASSET_ID_O32 is not null

        order by VC_ASSET_ID_O32 asc



     select distinct  VC_COMBI_ID_O32 combid, VC_COMBI_NAME_O32 combiname from PRT_PORTINFO 


                and VC_PORT_TYPE_1 = #{type1}


                and VC_PORT_TYPE_2 = #{type2}


                and VC_FUND_ID_O32 = #{fundid}


                and VC_ASSET_ID_O32 = #{assetid}

             AND  vc_fund_id_o32 IS NOT NULL
            AND  vc_fund_id_o32 NOT LIKE '%-%' 
			AND VC_COMBI_ID_O32 is not null          
			AND VC_COMBI_NAME_O32   is not null     
			 order by VC_COMBI_ID_O32 asc


  select count(*) as nums from PRT_PORTINFO 




                and VC_PORT_TYPE_1 = #{type1}


                and (

				VC_FUND_ID_O32 in  (select to_char(L_RULE_NO) from     T_COMP_RULEPORTBINDING where VC_PORT_CODE = #{code}) 


				or VC_COMBI_ID_O32 in (select to_char(L_RULE_NO) from     T_COMP_RULEPORTBINDING where VC_PORT_CODE = #{code})

				)


	SELECT * FROM T_COMP_DIMVALDIC 
	where VC_DIM_CODE = 'TL4_CODE' 

               and length(VC_ITEM_VALUE) = #{length}


               and "SUBSTR"(VC_ITEM_VALUE, 1, #{length}-1) = #{pid}
